import os
from flask import Flask, request, jsonify
from elasticapm.contrib.flask import ElasticAPM
from elasticapm.handlers.logging import LoggingHandler
import logging
import psycopg2

# Initialize Flask app
app = Flask(__name__)

# Configure Elastic APM
app.config['ELASTIC_APM'] = {
    'SERVICE_NAME': 'my-python-app',
    'SECRET_TOKEN': 'your_secret_token',
    'SERVER_URL': 'http://localhost:8200',
    'CAPTURE_BODY': 'all',
    'CAPTURE_HEADERS': True,
    'TRANSACTIONS_IGNORE_PATTERNS': ['OPTIONS'],
    'STACK_TRACE_LIMIT': 50,
    'CAPTURE_SQL_QUERIES': True
}

# Initialize Elastic APM
apm = ElasticAPM(app)

# Set up logging
handler = LoggingHandler(client=apm.client)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)
logger.addHandler(handler)

# Database connection
def get_db_connection():
    conn = psycopg2.connect(
        dbname=os.getenv('DB_NAME'),
        user=os.getenv('DB_USER'),
        password=os.getenv('DB_PASSWORD'),
        host=os.getenv('DB_HOST'),
        port=os.getenv('DB_PORT')
    )
    return conn

@app.route('/data', methods=['GET'])
def get_data():
    try:
        conn = get_db_connection()
        cur = conn.cursor()
        cur.execute('SELECT * FROM my_table')
        rows = cur.fetchall()
        cur.close()
        conn.close()
        return jsonify(rows)
    except Exception as e:
        logger.error('Error fetching data', exc_info=True)
        return jsonify({'error': 'Internal Server Error'}), 500

@app.route('/data', methods=['POST'])
def post_data():
    try:
        data = request.json
        conn = get_db_connection()
        cur = conn.cursor()
        cur.execute('INSERT INTO my_table (column1, column2) VALUES (%s, %s)', (data['column1'], data['column2']))
        conn.commit()
        cur.close()
        conn.close()
        return jsonify({'status': 'success'}), 201
    except Exception as e:
        logger.error('Error inserting data', exc_info=True)
        return jsonify({'error': 'Internal Server Error'}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)